import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] a = new int[n];
        for (int i = 0; i < n; i++) {
            a[i] = scanner.nextInt();
        }
        int m = a[n - 1];
        for (int i = n - 1; i >= 0; i--) {
            if (a[i] > m) {
                m = a[i];
            }
        }
        System.out.println(m);
    }
}

