const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let a = [];
readline.on('line', line => {
    if (i === 0) {
        n = parseInt(line);
    } else {
        a = line.split(' ').map(num => parseInt(num));
        let m = a[a.length - 1];
        for (let j = a.length - 1; j >= 0; j--) {
            if (a[j] > m) {
                m = a[j];
            }
        }
        console.log(m);
        readline.close();
    }
    i++;
});
